#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#define MAXN 100005
#define INF 0x3f3f3f3f

int T, N, A, B, a[MAXN];
int dist[MAXN][MAXN];
int popcount(int x) {
    int count = 0;
    while (x) {
        count += x & 1;
        x >>= 1;
    }
    return count;
}

void bfs(int start) {
    int queue[MAXN], front, rear;
    int visited[MAXN] = {0};
    for (int i = 1; i <= N; i++) dist[start][i] = INF;
    dist[start][start] = 0;
    queue[rear = 0] = start;
    front = 0;
    while (front <= rear) {
        int u = queue[front++];
        for (int v = 1; v <= N; v++) {
            if (v != u && dist[u][v] == INF - 1) {
                dist[start][v] = dist[start][u] + 1;
                queue[++rear] = v;
            }
        }
    }
}

int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                if (i != j) dist[i][j] = INF;
            }
        }
        for (int i = 1; i < N; i++) {
            scanf("%d %d", &A, &B);
            dist[A][B] = dist[B][A] = 1;
        }
        for (int i = 1; i <= N; i++) scanf("%d", &a[i]);
        for (int i = 1; i <= N; i++) bfs(i);
        long long ans = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                if (popcount(a[i] ^ a[j]) % 2 != dist[i][j] % 2) ans++;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

